mapper.select:
SELECT e.id AS enrollment_id, a.id AS activity_id, a.title, a.start_at, COALESCE(a.location_text, a.address) AS location, org.username AS organizer, e.status, e.waitlist_rank, GROUP_CONCAT(DISTINCT t.tag ORDER BY t.tag SEPARATOR ',') AS tags_csv FROM local_activity_enrollment e JOIN users u ON u.user_id = e.user_id JOIN local_activity a ON a.id = e.activity_id JOIN users org ON org.user_id = a.organizer_user_id LEFT JOIN local_activity_tag t ON t.activity_id = a.id WHERE u.username = #{username}
AND e.status = #{status}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR org.username LIKE CONCAT('%', #{keyword}, '%'))
AND a.start_at >= NOW()
AND a.start_at < NOW()
GROUP BY e.id, a.id, a.title, a.start_at, COALESCE(a.location_text, a.address), org.username, e.status, e.waitlist_rank ORDER BY a.start_at DESC

SELECT id, status, waitlist_rank
FROM local_activity_enrollment
WHERE activity_id = #{activityId}
  AND user_id = #{userId}
ORDER BY id DESC
LIMIT 1

SELECT id, status, waitlist_rank
FROM local_activity_enrollment
WHERE id = #{id}

mapper.update:
UPDATE local_activity_enrollment
SET waitlist_rank = waitlist_rank - 1,
    updated_at = NOW()
WHERE activity_id = #{activityId}
  AND status = 'waitlist'
  AND waitlist_rank > #{waitlistRank}
